INSERT INTO "public"."components" ("id", "name", "type", "description", "required_ingredients", "optional_ingredients", "recipe_steps", "created_at") VALUES
	('1f674fd0-9a1a-4ec7-9452-0fc78677e71f', 'メロン皮', 'topping', 'メロンパン用のクッキー生地', '{薄力粉,砂糖,卵,バター}', '{バニラエッセンス,バニラペースト,ベーキングパウダー}', '{バターと砂糖をすり混ぜてクリーム状にする,溶き卵を少しずつ加えてよく混ぜる,バニラを加えて混ぜる,薄力粉をふるい入れてさっくり混ぜる,生地をラップに包んで冷蔵庫で30分休ませる,丸めた菓子パン生地の上にメロン皮を薄く伸ばして被せ格子模様をつける}', '2026-05-14 00:06:06.145814+00'),
	('528f99fc-f4f8-4a24-998e-a42feef8f6f1', 'クランブル', 'topping', 'ザクザク食感のトッピング', '{薄力粉,砂糖,バター}', '{アーモンドパウダー,シナモン}', '{バターを小さく切って冷やす,薄力粉・砂糖・バターを指先でサラサラになるまで混ぜる,冷蔵庫で冷やしてから使う}', '2026-05-14 00:06:06.145814+00'),
	('e494565a-b49e-4e52-9979-e59de63cb3e9', '折り込みバターシート', 'sheet', 'クロワッサン・デニッシュ用の折り込みバター', '{バター}', '{バター}', '{バターを厚手のフィルムで挟みめん棒でたたいて適度に柔らかくする,12cm正方形になるようにフィルムを折り畳みめん棒で均一に伸ばす,形が整ったら冷蔵庫で冷やす}', '2026-05-14 00:06:06.145814+00'),
	('29b8b1e3-a7dc-4fdb-844f-caa3ac7a4d2c', 'チョコ折り込みシート', 'sheet', 'チョコレート風味の折り込みシート', '{バター,チョコレート}', '{ココアパウダー}', '{バターを室温で柔らかくする,チョコレートを湯煎で溶かしてバターに混ぜる,ラップで挟んで薄く伸ばし冷蔵庫で固める}', '2026-05-14 00:06:06.145814+00'),
	('b4b889bb-1b62-438b-9fc8-49e490264f6b', 'あんこ', 'filling', '小豆から作る自家製あんこ', '{小豆,砂糖}', '{塩}', '{成形時に生地を丸く広げ、中央にあんこをのせて包む。,とじ目を下にして並べる。}', '2026-05-13 08:08:16.829681+00'),
	('0d8f3c5c-5460-4c7a-9a41-929db057048f', 'カスタードクリーム', 'filling', '牛乳・卵・砂糖・薄力粉で作る基本のカスタード', '{卵,牛乳,砂糖,薄力粉}', '{バター,バニラビーンズ,バニラエッセンス,バニラペースト}', '{成形時に生地を広げ、カスタードクリームをのせて包む。,クリームが漏れないよう、とじ目をしっかり閉じる。}', '2026-05-13 08:08:16.829681+00'),
	('f533bcd1-047c-4426-b51a-a524b4816299', 'チョコクリーム', 'filling', 'チョコレートを使ったリッチなフィリング', '{チョコレート}', '{生クリーム,バター}', '{成形時に生地を広げ、カスタードクリームをのせて包む。,クリームが漏れないよう、とじ目をしっかり閉じる。}', '2026-05-13 08:08:16.829681+00'),
	('afdef297-ed1c-45ae-bc46-6930630f88c7', 'ジャム', 'filling', 'フルーツジャム', '{フルーツ,砂糖}', '{レモン汁}', '{成形時に生地を広げ、中央にジャムをのせて包む。,焼成中に漏れないよう、生地の端をしっかり密着させる。}', '2026-05-13 08:08:16.829681+00');
INSERT INTO "public"."recipes" ("id", "name", "texture", "time", "servings", "sweetness", "difficulty_level", "catchcopy", "feature", "recommend", "ingredients", "steps", "fermentation", "point", "created_at") VALUES
	('3f4efa67-1d78-46d1-b657-fd76cd09b5bc', 'レーズンリンゴパン', 'しっとり', '約50分', '4個分', '甘め', '簡単', 'レーズンとリンゴのハーモニー', 'しっとり・甘め・強力粉使用', '一番簡単', '["強力粉 200g", "リンゴ 100g", "レーズン 150g", "水 100ml", "塩 5g", "砂糖 15g", "酵母 5g"]', '["【下準備】材料を準備する", "【捏ね①】強力粉、水、塩、砂糖、酵母を混ぜて10分間捏ねる", "【一次発酵】28℃で45分発酵させる", "【ガス抜き】ガス抜きを行う", "【ベンチタイム】20分間ベンチタイムを行う", "【成形】リンゴとレーズンを加えて成形する", "【二次発酵】35℃で20〜30分発酵させる", "【焼成】180℃で15分焼成する", "【仕上げ】焼き上がりを確認する", "【冷却】パンを冷却する"]', '一次発酵 28℃・45分 / 二次発酵 35℃・20〜30分', '失敗しないコツは、一次発酵と二次発酵の温度と時間を正確に守ることです。また、レーズンとリンゴを加える際に丁寧に混ぜることが重要です。', '2026-04-28 05:48:01.068223+00'),
	('71e17b5b-9fcc-4be3-bfd7-a186421fba14', 'シンプルリンゴパン', 'ふんわり', '約45分', '4個分', '甘め', '簡単', '牛乳たっぷりでしっとりふんわり仕上げ', '甘め・しっとり・牛乳使用', '一番簡単', '["リンゴ 200g", "強力粉 250g", "牛乳 120ml"]', '["【下準備】材料を準備し、リンゴを洗って皮を剥き、種を取り除いて200gの分量に切ります。", "【捏ね①】強力粉、牛乳を混ぜて、リンゴを加えて混ぜます。", "【一次発酵】28℃で60分間発酵させます。", "【ガス抜き】発酵した生地を折りたたみ、ガスを抜きます。", "【ベンチタイム】10分間休ませます。", "【成形】生地を4等分に分け、棒状に成形します。", "【二次発酵】35℃で30〜40分間発酵させます。", "【焼成】180℃のオーブンで20分間焼きます。", "【仕上げ】焼き上がったパンを5分間休ませます。", "【包装】パンをラップで包み、温かい状態で提供します。"]', '一次発酵 28℃・60分 / 二次発酵 35℃・30〜40分', '一次発酵の際に温度を一定に保つことが重要です。二次発酵の際に過度に発酵しないように注意しましょう。', '2026-04-28 05:48:36.077149+00'),
	('596791f4-ba77-4016-a716-623af298ecbd', '本格レーズンパン', 'しっとり', '約3時間', '6個分', '中程度', '本格', 'レーズンの風味が際立つ本格レーズンパン', '中程度・しっとり・本格', '一番本格的なパン', '["強力粉 700g", "砂糖 150g", "ドライイースト 15g", "レーズン 250g", "塩 10g"]', '["【下準備】強力粉、砂糖、ドライイースト、塩を測量する", "【レーズン準備】レーズンを水で洗い、水気を切る", "【水温調整】25℃の水を用意する", "【生地混ぜ】強力粉、砂糖、ドライイースト、塩を混ぜ、レーズンを加える", "【一次発酵】28℃で90分発酵させる", "【ガス抜き】生地を折り、空気を抜く", "【ベンチタイム】25℃で45分休ませる", "【成形】バット状に成形する", "【二次発酵】35℃で45〜60分発酵させる", "【焼成】220℃で30分焼く", "【仕上げ】焼けたパンを冷まして完成させる", "【保管】室温で保管する"]', '一次発酵 28℃・90分 / 二次発酵 35℃・45〜60分', 'レーズンの風味を引き出すために、発酵時間を長くすることが重要です。一次発酵と二次発酵の温度と時間を厳密に守ることで、パンがしっとり仕上がります。', '2026-04-28 06:09:38.72844+00'),
	('238d8e45-ad86-4b62-9d2a-0b34d57b9616', 'ふわふわミルクブレッド', 'ふんわり', '約60分', '4個分', '甘め', '簡単', '牛乳たっぷりでしっとりふんわり仕上げ', '甘め・しっとり・牛乳使用', '一番簡単', '["強力粉 200g", "牛乳 130ml", "バター 20g", "砂糖 大さじ2", "ドライイースト 3g", "塩 小さじ1/2"]', '["【下準備】バターは室温に戻す", "【捏ね①】粉類を混ぜる", "【捏ね②】牛乳を加えてまとめる", "【一次発酵】28℃で40分", "【成形】4等分にして丸める", "【二次発酵】35℃で20分", "【焼成】180℃で15分", "【仕上げ】網の上で冷ます"]', '一次発酵 28℃・40分 / 二次発酵 35℃・20分', '牛乳は人肌程度に温めると発酵が安定します。', '2026-04-28 06:21:13.859757+00'),
	('d4c78715-1272-452e-a1f5-6ffa6248729c', 'シンプルドライイーストパン', 'しっとり', '約45分', '4個分', '控えめ', '簡単', '手軽に作れる、しっとりパン', 'シンプル・手軽・ドライイースト使用', '一番簡単', '["強力粉 250g", "ドライイースト 5g", "塩 5g", "水 150ml"]', '["【下準備】強力粉、ドライイースト、塩を準備する", "【捏ね①】水を加え、こねる", "【一次発酵】28℃で60分発酵させる", "【ガス抜き】成分を混ぜて空気を抜く", "【ベンチタイム】10分休ませる", "【成形】四角形に成形する", "【二次発酵】35℃で30〜40分発酵させる", "【焼成】180℃で20分焼く", "【仕上げ】焼けたら冷やす", "【ラストチェック】完成したパンをチェックする"]', '一次発酵 28℃・60分 / 二次発酵 35℃・30〜40分', '一度発酵させた後、十分にガス抜きを行い、二次発酵後に焼成することで、しっとりしたパンを作ることができます。焼成時には、180℃で20分焼くことをお勧めします。', '2026-04-28 07:23:34.745253+00'),
	('1624ccea-f927-4b5b-9fd2-73204575c527', '食パン風ミルクパン', 'ふんわり', '約2時間', '4個分', '甘め', '簡単', '牛乳たっぷりでしっとりふんわり仕上げ', '甘め・しっとり・牛乳使用', '材料少ない', '["強力粉 250g", "薄力粉 50g", "無塩バター 30g", "塩 3g", "砂糖 10g", "グラニュー糖 5g", "イースト 3g", "牛乳 150ml"]', '["【初期下準備】材料を準備し、イーストを牛乳に溶かす", "【捏ね①】強力粉、薄力粉、砂糖、グラニュー糖、塩を混ぜ、イースト溶液と無塩バターを加えて混ぜる", "【一次発酵】冷蔵庫で8時間発酵させる", "【ガス抜き】一度発酵した生地を取り出してガス抜きする", "【ベンチタイム】20分間休ませる", "【成形】成形する", "【二次発酵】室温（約20℃）で45分発酵させる", "【焼成】オーブンを170℃に設定し、15分間焼く", "【仕上げ】焼き上がったパンを冷ます", "【完成】ミルクパンをカットして完成"]', '一次発酵 4℃・8時間 / 二次発酵 20℃・45分', 'イーストを十分に溶かさないこと、生地を過度に捏ねないこと', '2026-04-28 10:56:40.328011+00'),
	('271b9168-c72a-4dbc-875d-8f92652f308b', 'シンプルチョコレートパン', 'ふんわり', '約2時間30分', '6個分', '甘め', '簡単', 'チョコレートと牛乳のマッチ gemacht', '甘め・しっとり・チョコレート使用', '一番簡単', '["強力粉 300g", "薄力粉 100g", "無塩バター 50g", "塩 5g", "砂糖 20g", "グラニュー糖 10g", "イースト 5g", "チョコレート 100g", "牛乳 200ml"]', '["【初期下準備】材料を準備し、イーストを牛乳に溶かす", "【捏ね①】強力粉、薄力粉、砂糖、グラニュー糖、塩を混ぜ、イースト溶液と無塩バターを加えて混ぜる", "【一次発酵】冷蔵庫で8時間発酵させる", "【ガス抜き】一度発酵した生地を取り出してガス抜きする", "【ベンチタイム】30分間休ませる", "【成形】チョコレートを入れて成形する", "【二次発酵】室温（約20℃）で1時間発酵させる", "【焼成】オーブンを180℃に設定し、20分間焼く", "【仕上げ】焼き上がったパンを冷ます", "【完成】チョコレートパンをカットして完成"]', '一次発酵 4℃・8時間 / 二次発酵 20℃・1時間', 'チョコレートを十分に溶かさないこと、生地を過度に捏ねないこと', '2026-04-28 10:58:11.396101+00'),
	('5699e32e-53ac-40d7-856d-bfe6697e4d4a', 'バターパン', 'ハード系', '約12時間', '1斤', '中程度', '本格', 'バターの風味が豊かなパン', 'バター風味・低温長時間発酵・ハード系', '一番バター風味', '["強力粉 500g", "有塩バター 150g", "グラニュー糖 20g", "ハチミツ 10g", "ドライイースト 10g", "塩 5g"]', '["【下準備】材料を準備し、強力粉とドライイーストを別々に量ります", "【捏ね①】ホームベーカリーで強力粉、有塩バター、グラニュー糖、ハチミツを混ぜ、5分間捏ねます", "【一次発酵】ホームベーカリーで一次発酵を開始、28℃・60分間発酵します", "【ガス抜き】ベーカリーを停止し、生地を取り出してガス抜きを行います", "【ベンチタイム】室温で30分間ベンチタイムを行います", "【成形】生地を成形し、冷蔵庫で8〜12時間低温長時間発酵を行います", "【二次発酵】冷蔵庫から取り出して、35℃・30〜40分間二次発酵を行います", "【焼成】ホームベーカリーで220℃・25〜30分間焼成します", "【仕上げ】焼き上がったパンを冷まします", "【仕上げ後】完全に冷ましたら、カットして提供します"]', '一次発酵 28℃・60分 / 二次発酵 35℃・30〜40分', '低温長時間発酵により本格的なクラストが形成され、プロ風のパンを作ることができます。一次発酵の際に十分な時間を確保することが重要です。', '2026-04-29 00:52:16.364371+00'),
	('6e4cf832-985b-4803-8407-f847339a67e5', 'シンプルウインナーパン', 'ふんわり', '約20分', '4〜6個分', '控えめ', '超簡単', '手軽に簡単に作れる、ふんわりパン', 'シンプル・手軽・卵使用', '一番簡単', '["卵 2個", "ウインナー 4本", "玉ねぎ 100g", "ナス 100g", "キャベツ 100g"]', '["【材料準備】卵、ウインナー、玉ねぎ、ナス、キャベツを準備する", "【下準備】フライパンを中火で熱する", "【材料混ぜ】卵、ウインナー、玉ねぎ、ナス、キャベツを混ぜ合わせる", "【フライパンに流し込む】材料をフライパンに流し込む", "【焼成】中火で5分焼く", "【反転】ふり返す", "【焼成2】中火で5分焼く", "【盛り付け】盛り付ける", "【仕上げ】出来上がり", "【提供】提供する"]', 'なし', '卵をよく混ぜることでふんわり仕上がります。材料を混ぜる際に、ウインナーを細かく切ることで均一に火が通ります。', '2026-04-29 01:12:11.83676+00'),
	('75377e20-d106-4ff7-81b6-186cd3ce0d86', 'リッチブラウニーパン', 'しっとり', '約3時間', '8個分', '甘め', '本格', '黒糖とチョコレートの贅沢な一品', 'リッチ・ブラウン・チョコレート使用', '一番美味しい', '["強力粉 400g", "薄力粉 150g", "無塩バター 70g", "有塩バター 30g", "塩 10g", "黒糖 50g", "グラニュー糖 20g", "イースト 10g", "チョコレート 150g", "卵 2個", "牛乳 250ml"]', '["【初期下準備】材料を準備し、イーストを牛乳に溶かす", "【捏ね①】強力粉、薄力粉、黒糖、グラニュー糖、塩を混ぜ、イースト溶液と無塩バター、有塩バターを加えて混ぜる", "【一次発酵】冷蔵庫で10時間発酵させる", "【ガス抜き】一度発酵した生地を取り出してガス抜きする", "【ベンチタイム】45分間休ませる", "【成形】チョコレートを入れて成形する", "【二次発酵】室温（約20℃）で1時間30分発酵させる", "【焼成】オーブンを190℃に設定し、25分間焼く", "【仕上げ】焼き上がったパンを冷ます", "【チョコレートコーティング】チョコレートを溶かしてパンにコーティングする", "【完成】ブラウニーパンをカットして完成"]', '一次発酵 4℃・10時間 / 二次発酵 20℃・1時間30分', '黒糖を十分に溶かさないこと、チョコレートコーティングの際に手が震えないこと', '2026-04-30 02:00:03.864229+00'),
	('9eb80d42-ad68-48d7-9498-ff98e301fd25', 'リンゴプロセスチーズパンS', 'ふんわり', '約1時間', '6個分', '甘め', '本格', '小さな贅沢', 'ふんわり・プロセスチーズ・リンゴ', '一番コンパクト', '["強力粉 250g", "牛乳 163ml", "無塩バター 25g（室温に戻す）", "砂糖 20g", "塩 5g", "ドライイースト 5.8g"]', '["【下準備】無塩バターは室温に戻す。型に薄く油を塗る。牛乳は人肌（35℃程度）に温める。", "【混ぜる】ボウルに強力粉・砂糖・塩を入れて軽く混ぜる。温めた牛乳にドライイーストを溶かして加え、カードや手でひとまとめにする。", "【捏ね】台に出して8〜10分こねる。表面がなめらかになったら室温のバターを加え、さらに5分こねる。生地を薄く伸ばして半透明の膜（グルテン膜）ができればOK。（目安：約15分）", "【一次発酵】丸めてボウルに入れラップをかけ、30℃で発酵させる。指で押して跡がゆっくり戻ればOK。（目安：30℃・30分）", "【ガス抜き・分割】打ち粉をした台に出し、手のひらで軽く押してガスを抜く。均等に分割して丸め直す。", "【ベンチタイム】丸めた生地に濡れ布巾をかけて休ませる。生地がリラックスして成形しやすくなる。（目安：10〜15分）", "【成形】ガスを抜きながら好みの形に成形する。とじ目をしっかり閉じて型や天板に並べる。", "【二次発酵】35℃で発酵させる。型の8〜9分目まで膨らめばOK。（目安：35℃・20分）", "【焼成】オーブンを180℃に予熱する。15分焼く。焼き色がついたらアルミホイルをかぶせてOK。（目安：180℃・15分）", "【仕上げ】焼き上がったらすぐ型から出し、網の上で側面を下にして冷ます。粗熱が取れたら完成。"]', '一次発酵 30℃・30分 / 二次発酵 35℃・20分', '材料をよく混ぜる', '2026-04-30 07:18:24.595921+00'),
