	('11290597-a1ba-430e-98e2-c8b3b4006280', 'croissant', 'アップルデニッシュ', '{りんご}', '{シナモン,砂糖}', 'クロワッサン生地に甘煮リンゴをのせたデニッシュ', 'りんごを薄切りにして砂糖・シナモンで炒めてフィリングを作る。成形後にのせて焼く。', 'croissant', '2026-05-12 05:49:44.522341+00'),
