	('39cc797d-2070-47d6-9a78-34a6366f66ca', 'simple', 'チーズパン', '{チーズ}', '{ハム,パセリ}', '生地にチーズを練り込んだ風味豊かなパン', 'チーズは角切りにして捏ね上がった生地に折り込む。', 'standard', '2026-05-12 05:49:44.522341+00'),
	('97159d69-7dc1-44c8-9dc2-2fa7f085413f', 'simple', 'レーズンパン', '{レーズン}', '{シナモン,くるみ}', 'レーズンをたっぷり折り込んだ甘いパン', 'レーズンは水で戻してから捏ね後に折り込む。', 'standard', '2026-05-12 05:49:44.522341+00'),
	('aabd60cf-2f99-4038-ba58-4e63c1867dfa', 'simple', 'あんぱん', '{あんこ}', '{ごま}', '甘い生地にあんこを包んだ定番の菓子パン', '成形時に30〜40gのあんこを包む。包み口をしっかり閉じる。表面にごまをふる。', 'standard', '2026-05-12 05:49:44.522341+00'),
	('ccc17c9b-afb2-4198-be30-144be2723896', 'simple', 'カレーパン', '{カレー}', '{パン粉}', 'カレーを包んで揚げた定番の惣菜パン', '成形時にカレーフィリングを包む。パン粉をまぶして170℃の油で揚げる。', 'standard', '2026-05-12 05:49:44.522341+00'),
