	('7f9c852a-ee17-48ef-93c4-539b6df03b1e', 'hard', 'オリーブフォカッチャ', '{オリーブ}', '{ローズマリー,塩}', 'フォカッチャ生地にオリーブをトッピングした本格イタリアパン', '二次発酵後にディンプルを作り、オリーブをのせてオリーブオイルをかけて焼く。', 'focaccia', '2026-05-12 05:49:44.522341+00'),
	('c1a059f4-aa72-4089-938d-2558adc9ffb6', 'hard', 'ベーコンフォカッチャ', '{ベーコン}', '{チーズ,ローズマリー}', 'フォカッチャにベーコンをたっぷりのせた食事系パン', '二次発酵後にディンプルを作り、ベーコンをのせて焼く。', 'focaccia', '2026-05-12 05:49:44.522341+00'),
	('531843f3-72e0-401a-a56a-950b4b1333ec', 'hard', 'ガーリックフォカッチャ', '{にんにく}', '{パセリ,オリーブオイル}', 'にんにくの香りが食欲をそそるフォカッチャ', '二次発酵後ににんにくをスライスしてのせ、オリーブオイルをかけて焼く。', 'focaccia', '2026-05-12 05:49:44.522341+00'),
